INSERT INTO ref_capaian_pembelajaran (id, fase, mata_pelajaran, elemen, deskripsi_cp, 'Umum', 'b7ccdf3d-93ef-4a2c-948f-4e16c8adf85a', 'B', 'IPAS', 'Peserta didik dapat mengidentifikasi siklus hidup makhluk hidup, wujud zat dan perubahannya, serta memahami sejarah lokal dan keanekaragaman budaya di lingkungan provinsinya.');
INSERT INTO ref_capaian_pembelajaran (id, fase, mata_pelajaran, elemen, deskripsi_cp, 'Umum', '5a63f907-b941-4416-a8d7-9e48ae41393a', 'C', 'IPAS', 'Peserta didik mampu menganalisis sistem organ tubuh manusia, fenomena alam, pemanfaatan energi, serta sejarah nasional dan interaksi sosial-ekonomi di Indonesia.');
